function uuidv4() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function (c) {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

const root = $input.first().json || {};
const body = root.body || root;
const replay = !!root.replay;
const response_required = !!root.body && !replay;
const type = String(body.type || 'export').toLowerCase();
const email = String(body.email || '').trim().toLowerCase();
const tenant_id = body.tenant_id || root.tenant_id || null;
const request_id = body.request_id || body.id || uuidv4();
const event_id = body.event_id || body.request_id || request_id;
const correlation_id = replay && root.correlation_id ? root.correlation_id : uuidv4();
const invalid = !tenant_id || !email || !['export', 'delete'].includes(type);

return [{ json: {
  tenant_id,
  email,
  type,
  request_id,
  event_id,
  idem_key: 'dsar:' + event_id,
  replay,
  response_required,
  invalid,
  invalid_reason: invalid ? 'tenant_id, email, and type=export|delete are required' : null,
  correlation_id,
  execution_id: String($execution.id),
  supabase_url: ($env.SUPABASE_URL || '').replace(/\/$/, ''),
  service_key: $env.SUPABASE_SERVICE_KEY || '',
  telegram_token: $env.TELEGRAM_BOT_TOKEN || '',
  telegram_chat: $env.TELEGRAM_CHAT_ID || ''
} }];

const p = $('Normalize Request').first().json;
const H = {
  apikey: p.service_key,
  Authorization: 'Bearer ' + p.service_key,
  accept: 'application/json',
  'content-type': 'application/json'
};
const preferUpsert = Object.assign({}, H, { Prefer: 'resolution=merge-duplicates,return=representation' });
const preferPatch = Object.assign({}, H, { Prefer: 'return=representation' });

function enc(value) {
  return encodeURIComponent(String(value));
}
async function get(path) {
  return await this.helpers.httpRequest({ method: 'GET', url: p.supabase_url + path, headers: H, json: true });
}
async function post(path, body, headers = preferUpsert) {
  return await this.helpers.httpRequest({ method: 'POST', url: p.supabase_url + path, headers, body, json: true });
}
async function patch(path, body) {
  return await this.helpers.httpRequest({ method: 'PATCH', url: p.supabase_url + path, headers: preferPatch, body, json: true });
}

await post('/rest/v1/dsar_requests?on_conflict=id', [{
  id: p.request_id,
  tenant_id: p.tenant_id,
  email: p.email,
  type: p.type,
  status: 'processing',
  evidence: {
    correlation_id: p.correlation_id,
    source: p.replay ? 'replay' : 'webhook',
    received_at: new Date().toISOString()
  }
}]);

const tenantRows = await get('/rest/v1/tenants?id=eq.' + enc(p.tenant_id) + '&select=*');
if (!tenantRows || tenantRows.length === 0) {
  const evidence = {
    correlation_id: p.correlation_id,
    request_id: p.request_id,
    rejected_at: new Date().toISOString(),
    reason: 'tenant not found'
  };
  await patch('/rest/v1/dsar_requests?id=eq.' + enc(p.request_id), { status: 'rejected', evidence });
  return [{ json: { ok: false, request_id: p.request_id, tenant_id: p.tenant_id, email: p.email, type: p.type, evidence, notice: 'tenant not found' } }];
}

const tenant = tenantRows[0];
const seats = await get('/rest/v1/seats?tenant_id=eq.' + enc(p.tenant_id) + '&select=*');
const matchingSeats = (seats || []).filter((seat) => String(seat.user_email || '').toLowerCase() === p.email);
const entitlements = await get('/rest/v1/entitlements?tenant_id=eq.' + enc(p.tenant_id) + '&select=*');
const invoices = await get('/rest/v1/invoices?tenant_id=eq.' + enc(p.tenant_id) + '&select=*');
const health = await get('/rest/v1/health_signals?tenant_id=eq.' + enc(p.tenant_id) + '&select=metric,value,ts&order=ts.desc&limit=25');
const audits = await get('/rest/v1/audit_log?tenant_id=eq.' + enc(p.tenant_id) + '&select=service,step,status,payload,created_at&order=created_at.desc&limit=25');

let suppression = null;
if (p.type === 'delete') {
  const updatedSeats = await patch('/rest/v1/seats?tenant_id=eq.' + enc(p.tenant_id) + '&user_email=eq.' + enc(p.email), {
    status: 'disabled'
  });
  suppression = {
    matching_seats_disabled: Array.isArray(updatedSeats) ? updatedSeats.length : 0,
    mode: 'suppression',
    note: 'Demo-safe suppression disables matching seats and stores evidence; tenant financial/audit records are retained.'
  };
}

const dsarPackage = {
  tenant: { id: tenant.id, name: tenant.name, plan: tenant.plan, region: tenant.region, status: tenant.status, health_score: tenant.health_score },
  subject: { email: p.email, matched_seats: matchingSeats },
  entitlements,
  invoices,
  health_signals: health,
  recent_audit: audits
};
const evidence = {
  correlation_id: p.correlation_id,
  request_id: p.request_id,
  tenant_id: p.tenant_id,
  email: p.email,
  type: p.type,
  completed_at: new Date().toISOString(),
  package: dsarPackage,
  suppression
};

await patch('/rest/v1/dsar_requests?id=eq.' + enc(p.request_id), {
  status: 'completed',
  evidence
});

let telegram_delivered = false;
let notice = null;
if (p.telegram_token && p.telegram_chat) {
  const text = [
    'FlowOps DSAR completed',
    'Type: ' + p.type,
    'Tenant: ' + tenant.name,
    'Subject: ' + p.email,
    'Request: ' + p.request_id,
    'Correlation: ' + p.correlation_id
  ].join('\n');
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.telegram.org/bot' + p.telegram_token + '/sendMessage',
      body: { chat_id: p.telegram_chat, text },
      json: true
    });
    telegram_delivered = true;
  } catch (e) {
    notice = 'telegram failed: ' + (e && e.message ? e.message : String(e));
  }
} else {
  notice = 'telegram skipped: TELEGRAM_BOT_TOKEN / TELEGRAM_CHAT_ID not set';
}

return [{ json: {
  ok: true,
  request_id: p.request_id,
  tenant_id: p.tenant_id,
  email: p.email,
  type: p.type,
  status: 'completed',
  matched_seat_count: matchingSeats.length,
  entitlement_count: (entitlements || []).length,
  invoice_count: (invoices || []).length,
  audit_count: (audits || []).length,
  suppression,
  telegram_delivered,
  notice
} }];
